class Solution:
    def splitIntoFibonacci(self, num: str) -> List[int]:
        def backtrack(start, path):
            if start == len(num):
                return len(path) >= 3
            for end in range(start + 1, len(num) + 1):
                s = num[start:end]
                if (len(s) > 1 and s[0] == '0') or int(s) > 2**31 - 1:
                    continue
                if len(path) < 2 or int(s) == path[-1] + path[-2]:
                    path.append(int(s))
                    if backtrack(end, path):
                        return True
                    path.pop()
            return False

        for i in range(1, len(num)):
            for j in range(i + 1, len(num)):
                a, b = num[:i], num[i:j]
                if (len(a) > 1 and a[0] == '0') or int(a) > 2**31 - 1:
                    continue
                if (len(b) > 1 and b[0] == '0') or int(b) > 2**31 - 1:
                    continue
                path = [int(a), int(b)]
                if backtrack(j, path):
                    return path
        return []
